protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed — throws at startup in EF Core 9 Cosmos provider.
    // Manage indexing policy in the Azure Portal, Bicep, or Terraform instead.

    modelBuilder.Entity<Product>(b =>
    {
        b.ToContainer("Products");

        // Preserve "Discriminator" property used by EF Core 8 documents and
        // existing direct SQL queries (c.Discriminator). EF Core 9 defaults to "$type".
        b.HasDiscriminator<string>("Discriminator");

        // Preserve the EF Core 8 compound id format ("Product|123").
        // Without this, EF Core 9 generates bare key values ("123") and
        // cannot find existing documents written by EF Core 8.
        b.HasRootDiscriminatorInJsonId(true);
    });
}

